qry:select.qry:xquery:
for $r in SQL(size:100,'     

	SELECT 
		CV.oi_cv,
		CV.d_ape_y_nom,
		CV.c_nro_doc,
		CV.c_sexo,
		CV.f_nacim,
		CV.c_pais ,
		CV.c_area,
		CV.te_nro,							
		CV.c_pais_cel,
		CV.c_area_cel,
		CV.te_celular,
		CV.c_nro_cuil,								
		CV.d_calle,
		CV.c_nro,
		CV.c_piso,
		CV.c_departamento,
		CV.d_email, 						 
		NAC.d_nacionalidad, 							
		CV.d_localidad,
		PCIA.d_provincia,											
		ECIVIL.d_estado_civil

		{%?($PARAM/@mode='CAR') {%,TDOC.c_tipo_documento %}{% %} %}
		{%?($PARAM/@mode='CV') {%,CV.c_tipo_documento %}{% %} %}						


	FROM							
	{%?($PARAM/@mode='CAR') 						
		{%
		POS01_CV as CV,
		PER20_TIPOS_DOC as TDOC, 					
		POS27_ASOCIA_CV_CAR as ACV 
		%} 
		{% %}  
	%}

	    {%?($PARAM/@mode='CV') 						
		{%
	       VW_BUSCAR_CV as CV					       
		%} 
		{% %}  
	%}


		,ORG12_NACIONALID as NAC							
		,ORG35_PROVINCIAS AS PCIA
		,ORG22_EST_CIVIL AS ECIVIL

	JOIN						 
		{%?($PARAM/@mode='CAR') 
		{%						
		CV.oi_cv INNER ACV.oi_cv, 
		CV.oi_tipo_documento LEFT OUTER TDOC.oi_tipo_documento,

		%} 
		{% %}  %}						           
		CV.oi_nacionalidad LEFT OUTER NAC.oi_nacionalidad						
		,CV.oi_provincia LEFT OUTER PCIA.oi_provincia 
		,CV.oi_estado_civil LEFT OUTER ECIVIL.oi_estado_civil

	WHERE
		1=1  
		{%?($PARAM/@mode='CAR')  {%AND ACV.oi_carpeta = {%=$PARAM/@oi_carpeta%}%}{% %} %}			

		{%?($PARAM/@mode='CV')  
		{%

		{%? ($PARAM/@campo_like_1!='')  {% AND (LIKE(CV.o_campo_like,\'%{%=$PARAM/@campo_like_1%}%\')%}{% %} %}
		{%? ($PARAM/@campo_like_2!='')  {% OR LIKE(CV.o_campo_like,\'%{%=$PARAM/@campo_like_2%}%\') %}{% %} %}
		{%? ($PARAM/@campo_like_3!='')  {% OR LIKE(CV.o_campo_like,\'%{%=$PARAM/@campo_like_3%}%\') %}{% %} %}
		{%? ($PARAM/@campo_like_4!='')  {% OR LIKE(CV.o_campo_like, \'%{%=$PARAM/@campo_like_4%}%\')%}{% %} %}
		{%? ($PARAM/@campo_like_5!='')  {% OR LIKE(CV.o_campo_like,\'%{%=$PARAM/@campo_like_5%}%\') %}{% %} %}
		{%? ($PARAM/@campo_like_6!='')  {% OR LIKE(CV.o_campo_like,\'%{%=$PARAM/@campo_like_6%}%\') %}{% %} %}
		{%? ($PARAM/@campo_like_7!='')  {% OR LIKE(CV.o_campo_like,\'%{%=$PARAM/@campo_like_7%}%\') %}{% %} %}
		{%? ($PARAM/@campo_like_8!='')  {% OR LIKE(CV.o_campo_like,\'%{%=$PARAM/@campo_like_8%}%\') %}{% %} %}
		{%? ($PARAM/@campo_like_9!='')  {% OR LIKE(CV.o_campo_like,\'%{%=$PARAM/@campo_like_9%}%\') %}{% %} %}
		{%? ($PARAM/@campo_like_10!='') {% OR LIKE(CV.o_campo_like,\'%{%=$PARAM/@campo_like_10%}%\')%}{% %} %}

		{%? ($PARAM/@campo_like_1!='')  {%) %}{% %} %}				

		{%? (($PARAM/@d_puesto!='') AND ($PARAM/@l_trab_puesto='1'))
			  {%
			  	 AND  UCASE(CV.d_puesto) = UCASE(\'{%=$PARAM/@d_puesto%}\')
			  	 AND isNull(CV.f_egreso) 					  
			  %}				  
			  {%
			  	  {%? ($PARAM/@d_puesto!='')
			  	    	{%
			  				AND UCASE(CV.d_puesto) = UCASE(\'{%=$PARAM/@d_puesto%}\')
			  	  		%}				  
			  				{%
			  				%}
			  		%}					    
			  %} 
		%}			

		{%? ($PARAM/@e_anio_desde!='')  {%AND  CV.aniosExperiencia>={%=$PARAM/@e_anio_desde%} %}{% %} %}				
		{%? ($PARAM/@e_anio_hasta!='')  {%AND  CV.aniosExperiencia<={%=$PARAM/@e_anio_hasta%} %}{% %} %}				

		{%? ($PARAM/@paramAreasLab!='')  {%AND CV.oi_area_lab {%=$PARAM/@paramAreasLab%}%}{% %} %}								
		{%? ($PARAM/@empresa_1!='')  {% AND (UCASE(CV.d_empresa) = UCASE(\'{%=$PARAM/@empresa_1%}\') %}{% %} %}
		{%? ($PARAM/@empresa_2!='')  {% OR UCASE(CV.d_empresa) = UCASE(\'{%=$PARAM/@empresa_2%}\') %}{% %} %}
		{%? ($PARAM/@empresa_3!='')  {% OR UCASE(CV.d_empresa) = UCASE(\'{%=$PARAM/@empresa_3%}\') %}{% %} %}
		{%? ($PARAM/@empresa_4!='')  {% OR UCASE(CV.d_empresa) = UCASE(\'{%=$PARAM/@empresa_4%}\') %}{% %} %}
		{%? ($PARAM/@empresa_5!='')  {% OR UCASE(CV.d_empresa) = UCASE(\'{%=$PARAM/@empresa_5%}\') %}{% %} %}
		{%? ($PARAM/@empresa_6!='')  {% OR UCASE(CV.d_empresa) = UCASE(\'{%=$PARAM/@empresa_6%}\') %}{% %} %}
		{%? ($PARAM/@empresa_7!='')  {% OR UCASE(CV.d_empresa) = UCASE(\'{%=$PARAM/@empresa_7%}\') %}{% %} %}
		{%? ($PARAM/@empresa_8!='')  {% OR UCASE(CV.d_empresa) = UCASE(\'{%=$PARAM/@empresa_8%}\') %}{% %} %}
		{%? ($PARAM/@empresa_9!='')  {% OR UCASE(CV.d_empresa) = UCASE(\'{%=$PARAM/@empresa_9%}\') %}{% %} %}
		{%? ($PARAM/@empresa_10!='') {% OR UCASE(CV.d_empresa) = UCASE(\'{%=$PARAM/@empresa_10%}\')%}{% %} %}				
		{%? ($PARAM/@empresa_1!='')  {%) %}{% %} %}                                             		
		{%? ($PARAM/@c_persona_cargo='E')  {%AND CV.l_per_cargo=1%}{% %} %} 	
		{%? ($PARAM/@d_titulo!='') {% AND UCASE(CV.d_estudio) = UCASE(\'{%=$PARAM/@d_titulo%}\') %}{% %} %}							
		{%? ($PARAM/@oi_nivel_estudio!='')  {%AND  CV.oi_nivel_estudio ={%=$PARAM/@oi_nivel_estudio%} %}{% %} %}
		{%? ($PARAM/@oi_estado_est!='')  {%AND  CV.oi_estado_est ={%=$PARAM/@oi_estado_est%} %}{% %} %}								

		{%? ($PARAM/@oi_idioma_1!='')  
		{%
			{%? ($PARAM/@oi_nivel_general_1!='5')  
				{%
					AND CV.oi_idioma = {%=$PARAM/@oi_idioma_1%}
					AND ( (CV.oi_nivel_lee>={%=$PARAM/@oi_nivel_general_1%}) 
							 OR (CV.oi_nivel_escribe>={%=$PARAM/@oi_nivel_general_1%}) 
							 OR (CV.oi_nivel_habla>={%=$PARAM/@oi_nivel_general_1%}) 
							) 
				%}
				{%							 		
			     AND CV.oi_idioma = {%=$PARAM/@oi_idioma_1%}
			     AND ( (CV.oi_nivel_lee = {%=$PARAM/@oi_nivel_general_1%}) 
							 OR (CV.oi_nivel_escribe = {%=$PARAM/@oi_nivel_general_1%}) 
							 OR (CV.oi_nivel_habla = {%=$PARAM/@oi_nivel_general_1%}) 
							 ) 
				%} 
			%}

		%}
		{% %} 					 
	 %}	

		 {%? ($PARAM/@oi_idioma_5!='')  
			{%
					{%? ($PARAM/@oi_nivel_general_5!='5')  
						{%
							AND CV.oi_idioma = {%=$PARAM/@oi_idioma_5%}
							AND ( (CV.oi_nivel_lee>={%=$PARAM/@oi_nivel_general_5%}) 
									 OR (CV.oi_nivel_escribe>={%=$PARAM/@oi_nivel_general_5%}) 
									 OR (CV.oi_nivel_habla>={%=$PARAM/@oi_nivel_general_5%}) 
									) 
						%}
						{%							 		
					     AND CV.oi_idioma = {%=$PARAM/@oi_idioma_5%}
					     AND ( (CV.oi_nivel_lee = {%=$PARAM/@oi_nivel_general_5%}) 
									 OR (CV.oi_nivel_escribe = {%=$PARAM/@oi_nivel_general_5%}) 
									 OR (CV.oi_nivel_habla = {%=$PARAM/@oi_nivel_general_5%}) 
									 ) 
						%} 
					%}

			%}
			{% %} 					 
		 %}									 		

		 {%? ($PARAM/@oi_idioma_2!='')  
			{%
					{%? ($PARAM/@oi_nivel_general_2!='5')  
						{%
							AND CV.oi_idioma = {%=$PARAM/@oi_idioma_2%}
							AND ( (CV.oi_nivel_lee>={%=$PARAM/@oi_nivel_general_2%}) 
									 OR (CV.oi_nivel_escribe>={%=$PARAM/@oi_nivel_general_2%}) 
									 OR (CV.oi_nivel_habla>={%=$PARAM/@oi_nivel_general_2%}) 
									) 
						%}
						{%							 		
					     AND CV.oi_idioma = {%=$PARAM/@oi_idioma_2%}
					     AND ( (CV.oi_nivel_lee = {%=$PARAM/@oi_nivel_general_2%}) 
									 OR (CV.oi_nivel_escribe = {%=$PARAM/@oi_nivel_general_2%}) 
									 OR (CV.oi_nivel_habla = {%=$PARAM/@oi_nivel_general_2%}) 
									 ) 
						%} 
					%}

			%}
			{% %} 					 
		 %}

		 {%? ($PARAM/@oi_idioma_3!='')  
			{%
					{%? ($PARAM/@oi_nivel_general_3!='5')  
						{%
							AND CV.oi_idioma = {%=$PARAM/@oi_idioma_3%}
							AND ( (CV.oi_nivel_lee>={%=$PARAM/@oi_nivel_general_3%}) 
									 OR (CV.oi_nivel_escribe>={%=$PARAM/@oi_nivel_general_3%}) 
									 OR (CV.oi_nivel_habla>={%=$PARAM/@oi_nivel_general_3%}) 
									) 
						%}
						{%							 		
					     AND CV.oi_idioma = {%=$PARAM/@oi_idioma_3%}
					     AND ( (CV.oi_nivel_lee = {%=$PARAM/@oi_nivel_general_3%}) 
									 OR (CV.oi_nivel_escribe = {%=$PARAM/@oi_nivel_general_3%}) 
									 OR (CV.oi_nivel_habla = {%=$PARAM/@oi_nivel_general_3%}) 
									 ) 
						%} 
					%}

			%}
			{% %} 					 
		 %}				

		 {%? ($PARAM/@oi_idioma_8!='')  
			{%
					{%? ($PARAM/@oi_nivel_general_8!='5')  
						{%
							AND CV.oi_idioma = {%=$PARAM/@oi_idioma_8%}
							AND ( (CV.oi_nivel_lee>={%=$PARAM/@oi_nivel_general_8%}) 
									 OR (CV.oi_nivel_escribe>={%=$PARAM/@oi_nivel_general_8%}) 
									 OR (CV.oi_nivel_habla>={%=$PARAM/@oi_nivel_general_8%}) 
									) 
						%}
						{%							 		
					     AND CV.oi_idioma = {%=$PARAM/@oi_idioma_8%}
					     AND ( (CV.oi_nivel_lee = {%=$PARAM/@oi_nivel_general_8%}) 
									 OR (CV.oi_nivel_escribe = {%=$PARAM/@oi_nivel_general_8%}) 
									 OR (CV.oi_nivel_habla = {%=$PARAM/@oi_nivel_general_8%}) 
									 ) 
						%} 
					%}

			%}
			{% %} 					 
		 %}

		 {%? ($PARAM/@oi_idioma_9!='')  
			{%
					{%? ($PARAM/@oi_nivel_general_9!='5')  
						{%
							AND CV.oi_idioma = {%=$PARAM/@oi_idioma_9%}
							AND ( (CV.oi_nivel_lee>={%=$PARAM/@oi_nivel_general_9%}) 
									 OR (CV.oi_nivel_escribe>={%=$PARAM/@oi_nivel_general_9%}) 
									 OR (CV.oi_nivel_habla>={%=$PARAM/@oi_nivel_general_9%}) 
									) 
						%}
						{%							 		
					     AND CV.oi_idioma = {%=$PARAM/@oi_idioma_9%}
					     AND ( (CV.oi_nivel_lee = {%=$PARAM/@oi_nivel_general_9%}) 
									 OR (CV.oi_nivel_escribe = {%=$PARAM/@oi_nivel_general_9%}) 
									 OR (CV.oi_nivel_habla = {%=$PARAM/@oi_nivel_general_9%}) 
									 ) 
						%} 
					%}

			%}
			{% %} 					 
		 %}			  			  
	    {%? ($PARAM/@c_nro_doc!='')  {%AND  LIKE(CV.c_nro_doc,\'%{%=$PARAM/@c_nro_doc%}%\') %}{% %} %}
		{%? ($PARAM/@d_nombres!='')  {%AND LIKE(CV.d_nombres,\'%{%=$PARAM/@d_nombres%}%\') %}{% %} %}
		{%? ($PARAM/@d_apellido!='')  {%AND LIKE(CV.d_apellido,\'%{%=$PARAM/@d_apellido%}%\') %}{% %} %}
		{%? ($PARAM/@c_sexo!='')  {%AND LIKE(CV.c_sexo,\'{%=$PARAM/@c_sexo%}\') %}{% %} %}
		{%? ($PARAM/@e_edad_desde!='')  {%AND  CV.edad>={%=$PARAM/@e_edad_desde%} %}{% %} %}				
		{%? ($PARAM/@e_edad_hasta!='')  {%AND  CV.edad<={%=$PARAM/@e_edad_hasta%} %}{% %} %}
		{%? ($PARAM/@oi_pais!='')  {%AND  CV.oi_pais ={%=$PARAM/@oi_pais%} %}{% %} %}
		{%? ($PARAM/@paramProvincia!='')  {%AND CV.oi_provincia {%=$PARAM/@paramProvincia%}%}{% %} %}
		{%? ($PARAM/@d_ciudad!='')  {%AND UCASE(CV.d_localidad) = UCASE(\'{%=$PARAM/@d_ciudad%}\') %}{% %} %}																												
		{%? ($PARAM/@l_foto='1')  {%AND isNotNull(CV.oi_foto)%}{% %} %}				 		

		{%? ($PARAM/@l_cv_sin_salario='')
			{%
				{%?($PARAM/@n_salario_desde!='') {% AND  CV.n_remuneracion>={%=$PARAM/@n_salario_desde%} %}{% %} %}	
				{%?($PARAM/@n_salario_hasta!='')  {%AND  CV.n_remuneracion<={%=$PARAM/@n_salario_hasta%} %}{% %} %}	
			%}
			{%
				{%?($PARAM/@n_salario_desde!='') {% AND ( (CV.n_remuneracion>={%=$PARAM/@n_salario_desde%}) OR (isNull(CV.n_remuneracion))) %}{% %} %}	
				{%?($PARAM/@n_salario_hasta!='')  {%AND ( (CV.n_remuneracion<={%=$PARAM/@n_salario_hasta%}) OR (isNull(CV.n_remuneracion))) %}{% %} %}					
			%}	
		%}					



		{%? ($PARAM/@f_actualizacion!='')  {% AND CV.f_actualizacion >= \'{%=$PARAM/@f_actualizacion%}\' %}{% %} %}		
	    {%? ($PARAM/@paramEstadoCV!='')  {% AND CV.c_estado {%=$PARAM/@paramEstadoCV %} %}{% %} %}
	    {%? ($PARAM/@oi_oferta_lab!='')  {%AND  CV.oi_oferta_lab ={%=$PARAM/@oi_oferta_lab%} %}{% %} %}


		 {%? ($PARAM/@l_leido='1')  {% AND CV.oi_usuario_sistema = \'{%=$PROXY/@ETTY%}\' %}{% %} %}

		 {%? ($PARAM/@l_leido='0')  
			{% AND  
			    CV.oi_cv NOT IN (SELECT AUX.oi_cv FROM POS01_CV_LEIDO as AUX WHERE AUX.oi_usuario_sistema  = \'{%=$PROXY/@ETTY%}\')
			  %}{% %} 
		%}							


		%}{% %} %}		


	{%?($PARAM/@mode='CV')  
	{%
	   GROUP BY
	   	CV.oi_cv,CV.d_ape_y_nom,CV.c_nro_doc,CV.c_sexo,CV.f_nacim,CV.c_pais,
		CV.c_area,CV.te_nro,CV.c_pais_cel,CV.c_area_cel,CV.te_celular,
		CV.c_nro_cuil,CV.d_calle,CV.c_nro,CV.c_piso,CV.c_departamento,CV.d_email, 						 
		NAC.d_nacionalidad,CV.d_localidad,PCIA.d_provincia,ECIVIL.d_estado_civil,CV.c_tipo_documento	    												
	%}{% %} %}		


')/ROWS/GROUPBY
